const SUPPLIER = 'KUEHNE';
const fail = (stage, msg, ctx) => {
  const suffix = ctx ? ' | ctx=' + JSON.stringify(ctx) : '';
  throw new Error('[' + SUPPLIER + ':' + stage + '] ' + msg + suffix);
};

const FILE_PATTERN = /(?:fact|invoice|basware).*\.pdf$/i;
const result = [];

for (const inputItem of $input.all()) {
  const binaryData = inputItem.binary;

  const messageId =
    inputItem.json.id ??
    inputItem.json.messageId ??
    null;

  if (!binaryData) {
    result.push({
      json: { ...inputItem.json, file_found: false, messageId }
    });
    continue;
  }

  const matchingKeys = Object.keys(binaryData).filter((key) =>
    FILE_PATTERN.test(binaryData[key].fileName || '')
  );

  if (matchingKeys.length === 0) {
    const availableFiles = Object.keys(binaryData)
      .map((k) => binaryData[k].fileName || k);
    result.push({
      json: { ...inputItem.json, file_found: false, messageId, availableFiles }
    });
    continue;
  }

  for (const key of matchingKeys) {
    result.push({
      json: {
        ...inputItem.json,
        file_found: true,
        messageId,
        attachmentKey: key,
        attachmentFileName: binaryData[key].fileName,
        attachmentMimeType: binaryData[key].mimeType
      },
      binary: { file: binaryData[key] }
    });
  }
}

return result;

const SUPPLIER = 'KUEHNE';
const log = (stage, msg, meta) => {
  const suffix = meta && Object.keys(meta).length ? ' ' + JSON.stringify(meta) : '';
  console.log('[' + SUPPLIER + ':' + stage + '] ' + msg + suffix);
};
const fail = (stage, msg, ctx) => {
  const suffix = ctx ? ' | ctx=' + JSON.stringify(ctx) : '';
  throw new Error('[' + SUPPLIER + ':' + stage + '] ' + msg + suffix);
};

const text = $input.item.json.text || '';
const messageId = $input.item.json.messageId || null;
const filename = $input.item.json.attachmentFileName || null;

function parseAmount(str) {
  if (!str) return null;
  const num = parseFloat(str.replace(/\s/g, ''));
  return isNaN(num) ? null : Math.round(num * 100) / 100;
}

// Invoice Number & Date
const invMatch = text.match(/INVOICE NO\.\s*\/\s*DATE\s+(\S+)\s+(\d{2})\.(\d{2})\.(\d{4})/);
if (!invMatch) fail('parse', 'Numéro de facture KN non trouvé', { messageId, filename });
const invoiceNumber = invMatch[1];
const invoiceDateISO = `${invMatch[4]}-${invMatch[3]}-${invMatch[2]}`;

// Due Date
const dueMatch = text.match(/DUE DATE\s+(\d{2})\.(\d{2})\.(\d{4})/);
const dueDateISO = dueMatch ? `${dueMatch[3]}-${dueMatch[2]}-${dueMatch[1]}` : null;

// KN Tracking
const knMatch = text.match(/KN TRACKING NO\.\s+([\d\s]+)/);
const knTracking = knMatch ? knMatch[1].trim().replace(/\s+/g, ' ') : null;

// Currency & Invoice Total
const totalMatch = text.match(/INVOICE TOTAL\s+(EUR|USD)\s+([\d\s]+\.\d{2})/);
if (!totalMatch) fail('parse', 'INVOICE TOTAL non trouvé', { messageId, invoice_number: invoiceNumber });
const currency = totalMatch[1];
const invoiceTotal = parseAmount(totalMatch[2]);

// SUBTOTAL
const subMatch = text.match(/SUBTOTAL\s+(?:EUR|USD)\s+([\d\s]+\.\d{2})\s+([\d\s]+\.\d{2})/);
const subtotal = subMatch ? parseAmount(subMatch[1]) : invoiceTotal;
const totalVAT = subMatch ? parseAmount(subMatch[2]) : 0;

// VAT breakdown
const vatRegex = /INVOICE VAT TOTAL\s+(?:[\d.]+\s*%|N\/A)\s+([1DI])\s+(?:EUR|USD)\s+([\d\s]+\.\d{2})\s+([\d\s]+\.\d{2})/g;
let amountTaxable = 0, vatOnTaxable = 0, amountDebours = 0, amountExempt = 0;
let m;
while ((m = vatRegex.exec(text)) !== null) {
  const cat = m[1], net = parseAmount(m[2]), vat = parseAmount(m[3]);
  if (cat === '1') { amountTaxable = net; vatOnTaxable = vat; }
  else if (cat === 'D') { amountDebours = net; }
  else if (cat === 'I') { amountExempt = net; }
}

// USD→EUR rate
const rateMatch = text.match(/USD\s*-\s*EUR\s*:\s*([\d.]+)/);
const usdEurRate = rateMatch ? parseFloat(rateMatch[1]) : null;

log('parse', 'OK', { invoice_number: invoiceNumber, currency, total: invoiceTotal });

return {
  invoice_number: invoiceNumber,
  invoice_date: invoiceDateISO,
  due_date: dueDateISO,
  kn_tracking: knTracking,
  currency,
  invoice_total: invoiceTotal,
  subtotal,
  total_vat: totalVAT,
  amount_taxable: amountTaxable,
  vat_on_taxable: vatOnTaxable,
  amount_debours: amountDebours,
  amount_exempt: amountExempt,
  usd_eur_rate: usdEurRate,
  source_pages: $input.item.json.numpages || null,
  messageId
};

