const data = $('Nettoyer les lignes1').item.json;
const messageId = data.messageId || null;

const VENDOR_ID         = '8564629000001168017';
const CURRENCY_EUR      = '8564629000000000109';
const CURRENCY_USD      = '8564629000000000097';
const TAX_ID_20         = '8564629000000163343';
const ACCOUNT_TRANSPORT = '8564629000000980076';
const ACCOUNT_DEBOURS   = '8564629000000980076';

const isUSD = data.currency === 'USD';
const currencyId = isUSD ? CURRENCY_USD : CURRENCY_EUR;

const lineItems = [];
if (isUSD) {
  lineItems.push({
    account_id: ACCOUNT_TRANSPORT,
    name: 'Fret maritime – Facture N°' + data.invoice_number,
    description: 'Facture KN N°' + data.invoice_number,
    quantity: 1,
    rate: data.invoice_total
  });
} else {
