      name: 'Logistique locale – Facture N°' + data.invoice_number,
      description: 'KN local (TVA 20%) – tracking ' + (data.kn_tracking || ''),
      quantity: 1,
      rate: data.amount_taxable,
      tax_id: TAX_ID_20
    });
  }
  if (data.amount_debours > 0) {
    lineItems.push({
      account_id: ACCOUNT_DEBOURS,
      name: 'Droits de douane – Facture N°' + data.invoice_number,
      description: 'KN débours douane – tracking ' + (data.kn_tracking || ''),
      quantity: 1,
      rate: data.amount_debours
    });
  }
  if (data.amount_exempt > 0) {
    lineItems.push({
      account_id: ACCOUNT_TRANSPORT,
      name: 'Fret/import exempt – Facture N°' + data.invoice_number,
      description: 'KN exempt import Art.262-II-14 CGI – tracking ' + (data.kn_tracking || ''),
      quantity: 1,
      rate: data.amount_exempt
    });
  }
}

const notes = 'KN Tracking: ' + (data.kn_tracking || 'N/A')
  + (isUSD ? '\nMontant original: ' + data.invoice_total.toFixed(2) + ' USD' : '');

const billBody = {
  vendor_id: VENDOR_ID,
  bill_number: data.invoice_number,
  date: data.invoice_date,
  due_date: data.due_date,
  payment_terms: 30,
  payment_terms_label: '30 net',
  reference_number: data.invoice_number,
  is_inclusive_tax: false,
  currency_id: currencyId,
  exchange_rate: 1,
  notes: notes,
  line_items: lineItems
};

const sourceBinary = $('Code in JavaScript').first().binary;
if (!sourceBinary || !sourceBinary.file) {
  fail('parse', 'Binaire PDF introuvable', { messageId, invoice_number: data.invoice_number });
}

return {
  json: {
    billJSON: JSON.stringify(billBody),
    invoice_number: data.invoice_number,
    invoice_date: data.invoice_date,
    currency: data.currency,
    invoice_total: data.invoice_total,
    is_usd: isUSD,
    line_items_count: lineItems.length,
    messageId
  },
  binary: { file: sourceBinary.file }
};

