const invoiceNumber = $('Nettoyer les lignes1').item.json.invoice_number;
const messageId = $('Nettoyer les lignes1').item.json.messageId || null;
const existingBill = $input.item.json.bills[0];

log('validate', 'Doublon ignoré', { invoice_number: invoiceNumber, existing_bill_id: existingBill.bill_id });

return {
  invoice_number: invoiceNumber,
  skipped: true,
  reason: 'already_exists',
  existing_bill_id: existingBill.bill_id,
  existing_bill_status: existingBill.status,
  messageId
};

const SUPPLIER = 'KUEHNE';
const items = $input.all();
const created = [];
const skipped = [];
let messageId = null;

for (const item of items) {
  const d = item.json;
  if (!messageId && d.messageId) messageId = d.messageId;
  if (d.created) {
    created.push({ type: 'bill', id: d.bill_id, number: d.bill_number, amount: d.total });
  } else if (d.skipped) {
    skipped.push({ reason: d.reason, ref: d.invoice_number, existing_id: d.existing_bill_id });
  }
}

// Fallback messageId from upstream
if (!messageId) {
  try { messageId = $('Code in JavaScript').first().json.messageId; } catch (_) {}
}

let status = 'success';
if (created.length === 0 && skipped.length > 0) status = 'skipped';
if (created.length > 0 && skipped.length > 0) status = 'partial';
if (created.length === 0 && skipped.length === 0) status = 'skipped';

const summaryParts = [];
if (created.length) summaryParts.push('Created ' + created.length + ' bill(s)');
if (skipped.length) summaryParts.push('Skipped ' + skipped.length + ' duplicate(s)');

return [{
  json: {
    status,
    supplier: SUPPLIER,
    message_id: messageId,
    records_created: created,
    records_skipped: skipped,
    summary: summaryParts.join(', ') || 'No invoices found'
  }
}];

